CREATE TABLE IF NOT EXISTS sys_dept (id BIGINT NOT NULL AUTO_INCREMENT COMMENT '主键', deleted TINYINT NOT NULL DEFAULT 0 COMMENT '逻辑删除', create_time DATETIME NULL COMMENT '创建时间', create_by BIGINT NULL COMMENT '创建人', update_time DATETIME NULL COMMENT '更新时间', update_by BIGINT NULL COMMENT '更新人', version INT NULL DEFAULT 0 COMMENT '乐观锁', parent_id BIGINT NOT NULL DEFAULT 0 COMMENT '父部门ID', ancestors VARCHAR(500) NULL COMMENT '祖级列表', dept_code VARCHAR(64) NOT NULL COMMENT '部门编码', dept_name VARCHAR(128) NOT NULL COMMENT '部门名称', sort_order INT NULL DEFAULT 0 COMMENT '排序号', leader VARCHAR(64) NULL COMMENT '负责人', phone VARCHAR(32) NULL COMMENT '联系电话', email VARCHAR(128) NULL COMMENT '邮箱', status INT NULL DEFAULT 1 COMMENT '状态(1=启用,0=禁用)', PRIMARY KEY (id), UNIQUE KEY uk_dept_code (dept_code), KEY idx_parent_id (parent_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='部门信息';
